269→    if(Number.isNaN(parsedLimit) || parsedLimit < 1 || parsedLimit > 10){
270→        throw new Error('limit should be an integer between 1 and 10');
271→    }
272→
273→    let url = `${BASE_URL}/journals/hottest-monthly?limit=${parsedLimit}`;
274→    if(userId){
275→        url += `&userId=${encodeURIComponent(userId)}`;
276→    }
277→
278→    const response = await apiRequest(url, {
279→        method: 'GET'
280→    });
281→
282→    if(!response.ok){
283→        const error = await response.json().catch(() => ({}));
284→        throw new Error(error?.error || 'failed to fetch monthly hottest journals');
285→    }
286→
287→    const data = await response.json();
288→    return data;
289→}
