892→export const getMonthlyHottestJournalsService = async(limit, userId) => {
893→    if(isNaN(limit) || limit < 1 || limit > 10){
894→        throw {status: 400, error: 'limit should be an integer between 1 and 10'};
895→    }
896→
897→    const parsedLimit = parseInt(limit);
898→    const now = new Date();
899→    const monthStartUtc = new Date(Date.UTC(now.getUTCFullYear(), now.getUTCMonth(), 1, 0, 0, 0, 0));
900→    const nextMonthStartUtc = new Date(Date.UTC(now.getUTCFullYear(), now.getUTCMonth() + 1, 1, 0, 0, 0, 0));
901→
902→    // Use server-side RPC to score and sort — avoids fetching ALL monthly posts
903→    const {data: rpcData, error: rpcError} = await supabase.rpc('get_monthly_hottest_journals', {
904→        p_limit: parsedLimit
905→    });
906→
907→    if(rpcError){
908→        console.error('supabase RPC error (get_monthly_hottest_journals):', rpcError.message);
909→        throw {status: 500, error: 'supabase error while fetching monthly hottest journals'};
910→    }
911→
912→    // Reshape RPC rows to match the format the client expects
913→    const journals = (rpcData || []).map((row) => ({
914→        id: row.id,
915→        user_id: row.user_id,
916→        title: row.title,
917→        content: row.content,
918→        post_type: row.post_type,
919→        canvas_doc: row.canvas_doc,
920→        created_at: row.created_at,
921→        privacy: row.privacy,
922→        views: row.views,
923→        is_repost: row.is_repost,
924→        repost_source_journal_id: row.repost_source_journal_id,
925→        repost_caption: row.repost_caption,
926→        users: {
927→            id: row.user_id,
928→            name: row.user_name,
929→            image_url: row.user_image_url,
930→            badge: row.user_badge
931→        },
932→        like_count: [{count: row.like_count}],
933→        comment_count: [{count: row.comment_count}],
934→        bookmark_count: [{count: row.bookmark_count}],
935→        hot_score: row.hot_score
936→    }));
937→
